import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  UserSearch,
  MapPin,
  Clock,
  Eye,
  Repeat,
  Smartphone,
  Monitor,
  Globe,
  ChevronDown,
  ChevronUp,
  ArrowRight,
} from "lucide-react";
import { format, formatDistanceToNow } from "date-fns";
import { zhCN, enUS, pt } from "date-fns/locale";
import { startOfDay, subDays } from "date-fns";
import { fetchAllPaginated } from "@/lib/paginatedQuery";

interface VisitorDetail {
  visitor_id: string;
  visit_count: number;
  first_visit: string;
  last_visit: string;
  country: string | null;
  city: string | null;
  pages: Array<{ page_type: string; target_id: string | null; created_at: string }>;
  user_agent: string | null;
  referer: string | null;
  user_id: string | null;
  is_return: boolean;
}

const parseUserAgent = (ua: string | null): { device: string; icon: typeof Monitor } => {
  if (!ua) return { device: "未知", icon: Monitor };
  const isMobile = /mobile|android|iphone|ipad/i.test(ua);
  return {
    device: isMobile ? "移动端" : "桌面端",
    icon: isMobile ? Smartphone : Monitor,
  };
};

const pageTypeEmoji: Record<string, string> = {
  home: "🏠",
  restaurant: "🍽️",
  activity: "🎉",
  restaurants: "📋",
  activities: "📅",
  community: "💬",
  post: "📝",
  map: "🗺️",
  profile: "👤",
  auth: "🔐",
  "join-us": "🤝",
  other: "📄",
};

interface Props {
  days: number;
}

const VisitorInsights = ({ days }: Props) => {
  const { t, i18n } = useTranslation();
  const [expandedVisitor, setExpandedVisitor] = useState<string | null>(null);
  const [showAll, setShowAll] = useState(false);

  const dateLocale = i18n.language === "zh" ? zhCN : i18n.language === "pt" ? pt : enUS;

  const { data: visitors, isLoading } = useQuery({
    queryKey: ["visitor-insights", days],
    queryFn: async (): Promise<VisitorDetail[]> => {
      let dateFilter: string | null = null;
      let dateFilterEnd: string | null = null;
      
      if (days === -1) {
        const yesterday = subDays(new Date(), 1);
        dateFilter = startOfDay(yesterday).toISOString();
        dateFilterEnd = startOfDay(new Date()).toISOString();
      } else if (days === 1) {
        dateFilter = startOfDay(new Date()).toISOString();
      } else if (days > 1) {
        dateFilter = startOfDay(subDays(new Date(), days - 1)).toISOString();
      }

      const views = await fetchAllPaginated(
        "page_views",
        "visitor_id,page_type,target_id,created_at,user_agent,referer,country,city,user_id",
        (query) => {
          if (dateFilter) query = query.gte("created_at", dateFilter);
          if (dateFilterEnd) query = query.lt("created_at", dateFilterEnd);
          return query.order("created_at", { ascending: false });
        }
      );

      // Group by visitor_id
      const visitorMap = new Map<string, VisitorDetail>();

      views.forEach((v: any) => {
        if (!visitorMap.has(v.visitor_id)) {
          visitorMap.set(v.visitor_id, {
            visitor_id: v.visitor_id,
            visit_count: 0,
            first_visit: v.created_at,
            last_visit: v.created_at,
            country: v.country,
            city: v.city,
            pages: [],
            user_agent: v.user_agent,
            referer: v.referer,
            user_id: v.user_id,
            is_return: false,
          });
        }
        const visitor = visitorMap.get(v.visitor_id)!;
        visitor.visit_count++;
        visitor.pages.push({
          page_type: v.page_type,
          target_id: v.target_id,
          created_at: v.created_at,
        });
        if (v.created_at < visitor.first_visit) visitor.first_visit = v.created_at;
        if (v.created_at > visitor.last_visit) visitor.last_visit = v.created_at;
        if (v.user_id) visitor.user_id = v.user_id;
      });

      // Check return visitors (visited on multiple different dates)
      visitorMap.forEach((visitor) => {
        const uniqueDates = new Set(
          visitor.pages.map((p) => p.created_at.split("T")[0])
        );
        visitor.is_return = uniqueDates.size > 1;
        // Sort pages by time ascending
        visitor.pages.sort((a, b) => a.created_at.localeCompare(b.created_at));
      });

      // Sort by visit count descending
      return Array.from(visitorMap.values()).sort(
        (a, b) => b.visit_count - a.visit_count
      );
    },
  });

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <Skeleton className="h-6 w-48" />
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {[...Array(5)].map((_, i) => (
              <Skeleton key={i} className="h-16" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  const totalVisitors = visitors?.length || 0;
  const returnVisitors = visitors?.filter((v) => v.is_return).length || 0;
  const mobileVisitors = visitors?.filter((v) => /mobile|android|iphone|ipad/i.test(v.user_agent || "")).length || 0;
  const displayVisitors = showAll ? visitors : visitors?.slice(0, 20);

  return (
    <div className="space-y-6">
      {/* Summary row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <UserSearch className="w-4 h-4" />
              独立访客
            </div>
            <div className="text-2xl font-bold">{totalVisitors}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Repeat className="w-4 h-4" />
              回头访客
            </div>
            <div className="text-2xl font-bold">
              {returnVisitors}
              <span className="text-sm font-normal text-muted-foreground ml-1">
                ({totalVisitors > 0 ? ((returnVisitors / totalVisitors) * 100).toFixed(0) : 0}%)
              </span>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Smartphone className="w-4 h-4" />
              移动端访客
            </div>
            <div className="text-2xl font-bold">
              {mobileVisitors}
              <span className="text-sm font-normal text-muted-foreground ml-1">
                ({totalVisitors > 0 ? ((mobileVisitors / totalVisitors) * 100).toFixed(0) : 0}%)
              </span>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-3">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Eye className="w-4 h-4" />
              人均浏览
            </div>
            <div className="text-2xl font-bold">
              {totalVisitors > 0
                ? ((visitors?.reduce((sum, v) => sum + v.visit_count, 0) || 0) / totalVisitors).toFixed(1)
                : 0}
              <span className="text-sm font-normal text-muted-foreground ml-1">页</span>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Visitor List */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <UserSearch className="w-5 h-5" />
            访客详情（谁在关注你）
          </CardTitle>
        </CardHeader>
        <CardContent>
          <ScrollArea className="max-h-[600px]">
            <div className="space-y-2">
              {displayVisitors?.map((visitor, index) => {
                const { device, icon: DeviceIcon } = parseUserAgent(visitor.user_agent);
                const isExpanded = expandedVisitor === visitor.visitor_id;

                return (
                  <div
                    key={visitor.visitor_id}
                    className="border rounded-lg overflow-hidden"
                  >
                    <button
                      className="w-full flex items-center justify-between p-3 hover:bg-muted/50 transition-colors text-left"
                      onClick={() =>
                        setExpandedVisitor(isExpanded ? null : visitor.visitor_id)
                      }
                    >
                      <div className="flex items-center gap-3 min-w-0">
                        <Badge
                          variant={index < 3 ? "default" : "secondary"}
                          className="w-6 h-6 p-0 justify-center shrink-0"
                        >
                          {index + 1}
                        </Badge>
                        <div className="min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <span className="font-mono text-xs text-muted-foreground truncate max-w-[100px]">
                              {visitor.visitor_id.slice(0, 8)}…
                            </span>
                            {visitor.user_id && (
                              <Badge variant="outline" className="text-xs bg-blue-50 dark:bg-blue-950 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-800">
                                已注册
                              </Badge>
                            )}
                            {visitor.is_return && (
                              <Badge variant="outline" className="text-xs bg-amber-50 dark:bg-amber-950 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-800">
                                <Repeat className="w-3 h-3 mr-1" />
                                回头客
                              </Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-3 mt-1 text-xs text-muted-foreground">
                            {(visitor.country || visitor.city) && (
                              <span className="flex items-center gap-1">
                                <MapPin className="w-3 h-3" />
                                {[visitor.city, visitor.country].filter(Boolean).join(", ")}
                              </span>
                            )}
                            <span className="flex items-center gap-1">
                              <DeviceIcon className="w-3 h-3" />
                              {device}
                            </span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-3 shrink-0">
                        <div className="text-right">
                          <div className="text-sm font-medium">{visitor.visit_count} 次浏览</div>
                          <div className="text-xs text-muted-foreground">
                            {formatDistanceToNow(new Date(visitor.last_visit), {
                              addSuffix: true,
                              locale: dateLocale,
                            })}
                          </div>
                        </div>
                        {isExpanded ? (
                          <ChevronUp className="w-4 h-4 text-muted-foreground" />
                        ) : (
                          <ChevronDown className="w-4 h-4 text-muted-foreground" />
                        )}
                      </div>
                    </button>

                    {isExpanded && (
                      <div className="border-t bg-muted/30 p-3">
                        <div className="text-xs text-muted-foreground mb-2">浏览路径：</div>
                        <div className="flex flex-wrap items-center gap-1">
                          {visitor.pages.slice(0, 20).map((page, pi) => (
                            <span key={pi} className="flex items-center gap-0.5">
                              {pi > 0 && (
                                <ArrowRight className="w-3 h-3 text-muted-foreground mx-0.5" />
                              )}
                              <Badge variant="outline" className="text-xs font-normal">
                                {pageTypeEmoji[page.page_type] || "📄"}{" "}
                                {page.page_type}
                                <span className="text-muted-foreground ml-1">
                                  {format(new Date(page.created_at), "HH:mm")}
                                </span>
                              </Badge>
                            </span>
                          ))}
                          {visitor.pages.length > 20 && (
                            <span className="text-xs text-muted-foreground">
                              …还有 {visitor.pages.length - 20} 条
                            </span>
                          )}
                        </div>
                        {visitor.referer && (
                          <div className="mt-2 text-xs text-muted-foreground">
                            <Globe className="w-3 h-3 inline mr-1" />
                            来源: {visitor.referer}
                          </div>
                        )}
                        <div className="mt-2 text-xs text-muted-foreground">
                          <Clock className="w-3 h-3 inline mr-1" />
                          首次访问: {format(new Date(visitor.first_visit), "yyyy-MM-dd HH:mm")}
                          {visitor.first_visit !== visitor.last_visit && (
                            <> → 最近: {format(new Date(visitor.last_visit), "yyyy-MM-dd HH:mm")}</>
                          )}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}

              {totalVisitors === 0 && (
                <div className="text-center py-8 text-muted-foreground">
                  暂无访客数据
                </div>
              )}
            </div>
          </ScrollArea>

          {totalVisitors > 20 && !showAll && (
            <div className="mt-4 text-center">
              <Button variant="outline" size="sm" onClick={() => setShowAll(true)}>
                查看全部 {totalVisitors} 位访客
              </Button>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default VisitorInsights;
